# Release Automation Script
# This script automates the release process: version increment, database deployment, tagging, and branch creation

$ErrorActionPreference = "Stop"

# Configuration
$srcRepo = "{{WEBAPI_DIR}}\src"
$databasePath = "{{DB_DIR}}"
$submodulePath = "{{WEBAPI_DIR}}\src\Identlock2.Domain"
$databaseHostname = "10.200.60.21"
$databaseName = "IdentLock2-2.9-Stage"
$sqlUser = "IdentLock2"
$sqlPassword = "shgZ4Kjk8xNduymekoZg"
$deploymentEnvironment = "Stage"

Write-Host "=== Release Automation Script ===" -ForegroundColor Cyan
Write-Host ""

# Step 1: Find the last release-win/{version} branch
Write-Host "Step 1: Finding last release-win/* branch..." -ForegroundColor Yellow
Push-Location $srcRepo
try {
    # Fetch latest branches from remote
    git fetch origin --prune

    # Get all release-win/* branches
    $branches = git branch -r | Where-Object { $_ -match 'origin/release-win/' }

    if ($branches.Count -eq 0) {
        throw "No release-win/* branches found"
    }

    # Parse versions from branch names
    $versions = @()
    foreach ($branch in $branches) {
        if ($branch -match 'release-win/(.+)$') {
            $versions += [PSCustomObject]@{
                Branch = $branch.Trim()
                Version = $matches[1].Trim()
            }
        }
    }

    # Sort versions (assumes semantic versioning like 2.9.0)
    $sortedVersions = $versions | Sort-Object {
        $parts = $_.Version -split '\.'
        [int]$parts[0] * 1000000 + [int]$parts[1] * 1000 + [int]$parts[2]
    }

    $lastVersion = $sortedVersions[-1].Version
    Write-Host "  Last version found: $lastVersion" -ForegroundColor Green

    # Step 2: Increment version
    Write-Host "`nStep 2: Incrementing version..." -ForegroundColor Yellow
    $versionParts = $lastVersion -split '\.'
    $versionParts[-1] = [int]$versionParts[-1] + 1
    $newVersion = $versionParts -join '.'
    Write-Host "  New version: $newVersion" -ForegroundColor Green

} finally {
    Pop-Location
}

# Step 3: Run database deployment
Write-Host "`nStep 3: Running database deployment..." -ForegroundColor Yellow
Push-Location $databasePath
try {
    $buildDate = Get-Date -Format "yyMMdd"

    & "$databasePath\publish-db.ps1" `
        -Version $newVersion `
        -DatabaseHostname $databaseHostname `
        -DatabaseName $databaseName `
        -SqlUser $sqlUser `
        -SqlPassword $sqlPassword `
        -DeploymentEnvironment $deploymentEnvironment `
        -BuildDate $buildDate

    if ($LASTEXITCODE -ne 0) {
        throw "Database deployment failed with exit code: $LASTEXITCODE"
    }

    Write-Host "  Database deployment successful!" -ForegroundColor Green

} catch {
    Write-Host "  ERROR: Database deployment failed: $_" -ForegroundColor Red
    Pop-Location
    exit 1
} finally {
    Pop-Location
}

# Step 4: Create and push tag in database repository
Write-Host "`nStep 4: Tagging database repository..." -ForegroundColor Yellow
Push-Location $databasePath
try {
    # Create tag
    git tag -a $newVersion -m "Release version $newVersion"
    Write-Host "  Created tag: $newVersion" -ForegroundColor Green

    # Push tag to remote
    git push origin $newVersion
    Write-Host "  Pushed tag to remote" -ForegroundColor Green

} catch {
    Write-Host "  ERROR: Failed to create/push tag: $_" -ForegroundColor Red
    Pop-Location
    exit 1
} finally {
    Pop-Location
}

# Step 5: Create and push release branch in src repository
Write-Host "`nStep 5: Creating release branch in src repository..." -ForegroundColor Yellow
Push-Location $srcRepo
try {
    # Create new branch
    $branchName = "release-win/$newVersion"
    git checkout -b $branchName
    Write-Host "  Created branch: $branchName" -ForegroundColor Green

    # Push branch to remote
    git push origin $branchName
    Write-Host "  Pushed branch to remote" -ForegroundColor Green

} catch {
    Write-Host "  ERROR: Failed to create/push branch: $_" -ForegroundColor Red
    Pop-Location
    exit 1
} finally {
    Pop-Location
}

# Step 6: Create and push tag in submodule
Write-Host "`nStep 6: Tagging submodule..." -ForegroundColor Yellow
Push-Location $submodulePath
try {
    # Create tag
    git tag -a $newVersion -m "Release version $newVersion"
    Write-Host "  Created tag: $newVersion" -ForegroundColor Green

    # Push tag to remote
    git push origin $newVersion
    Write-Host "  Pushed tag to remote" -ForegroundColor Green

} catch {
    Write-Host "  ERROR: Failed to create/push tag in submodule: $_" -ForegroundColor Red
    Pop-Location
    exit 1
} finally {
    Pop-Location
}

Write-Host "`n=== Release automation completed successfully! ===" -ForegroundColor Green
Write-Host "New version: $newVersion" -ForegroundColor Cyan
Write-Host "- Database deployed and tagged" -ForegroundColor White
Write-Host "- Release branch created: release-win/$newVersion" -ForegroundColor White
Write-Host "- Submodule tagged" -ForegroundColor White

