# Check-SqlProjectFiles.ps1
# Script to find .sql files not registered in the .sqlproj file

# Set default paths
$SqlProjPath = '{{DB_DIR}}\sqlserver\IdentLock2\IdentLock2.sqlproj'
$SearchFolder = '{{DB_DIR}}\sqlserver\IdentLock2'

# Override with command line arguments if provided
if ($args.Count -ge 1) {
    $SqlProjPath = $args[0]
}
if ($args.Count -ge 2) {
    $SearchFolder = $args[1]
}

# Ensure the paths exist
if (-not (Test-Path $SqlProjPath)) {
    Write-Host 'ERROR: SqlProj file not found at: ' -NoNewline -ForegroundColor Red
    Write-Host $SqlProjPath -ForegroundColor Red
    Read-Host 'Press Enter to exit'
    exit 1
}

if (-not (Test-Path $SearchFolder)) {
    Write-Host 'ERROR: Search folder not found at: ' -NoNewline -ForegroundColor Red
    Write-Host $SearchFolder -ForegroundColor Red
    Read-Host 'Press Enter to exit'
    exit 1
}

Write-Host 'Analyzing SQL Project...' -ForegroundColor Cyan
Write-Host 'Project file: ' -NoNewline -ForegroundColor Gray
Write-Host $SqlProjPath -ForegroundColor Gray
Write-Host 'Search folder: ' -NoNewline -ForegroundColor Gray
Write-Host $SearchFolder -ForegroundColor Gray
Write-Host ''

# Load the .sqlproj XML file
[xml]$sqlProj = Get-Content $SqlProjPath

# Get the base directory of the .sqlproj file
$projDirectory = Split-Path -Parent $SqlProjPath

# Extract all SQL files referenced in the project
$referencedFiles = @()

# Get Build includes
$sqlProj.Project.ItemGroup.Build | Where-Object { $_.Include } | ForEach-Object {
    $referencedFiles += $_.Include
}

# Get None includes (for .sql files)
$sqlProj.Project.ItemGroup.None | Where-Object { $_.Include -like '*.sql' } | ForEach-Object {
    $referencedFiles += $_.Include
}

# Get PostDeploy includes
$sqlProj.Project.ItemGroup.PostDeploy | Where-Object { $_.Include -like '*.sql' } | ForEach-Object {
    $referencedFiles += $_.Include
}

# Normalize paths (convert to relative paths with forward slashes replaced by backslashes)
$referencedFiles = $referencedFiles | ForEach-Object {
    $_.Replace('/', '\')
}

Write-Host "Found $($referencedFiles.Count) SQL files referenced in the project" -ForegroundColor Green
Write-Host ''

# Find all .sql files in the search folder (excluding Migrations and obj folders)
$allSqlFiles = Get-ChildItem -Path $SearchFolder -Filter '*.sql' -Recurse -File | Where-Object {
    $_.FullName -notmatch '\\Migrations\\' -and 
    $_.FullName -notmatch '\\obj\\' -and
    $_.Extension -eq '.sql'
}

Write-Host "Found $($allSqlFiles.Count) SQL files in the folder structure (excluding Migrations and obj folders)" -ForegroundColor Green
Write-Host ''

# Compare and find unregistered files
$unregisteredFiles = @()

foreach ($file in $allSqlFiles) {
    # Get relative path from project directory
    $relativePath = $file.FullName.Substring($projDirectory.Length + 1)

    # Check if this file is in the referenced list
    if ($referencedFiles -notcontains $relativePath) {
        $unregisteredFiles += @{
            FullPath = $file.FullName
            RelativePath = $relativePath
            Name = $file.Name
        }
    }
}

# Display results
if ($unregisteredFiles.Count -eq 0) {
    Write-Host 'All SQL files are registered in the project!' -ForegroundColor Green
    Read-Host 'Press Enter to exit'
    exit 0
}

Write-Host "Found $($unregisteredFiles.Count) unregistered SQL files:" -ForegroundColor Yellow
Write-Host ('=' * 80) -ForegroundColor Yellow
foreach ($file in $unregisteredFiles) {
    Write-Host "  - $($file.RelativePath)" -ForegroundColor White
}
Write-Host ('=' * 80) -ForegroundColor Yellow
Write-Host ''

# Ask user what to do
Write-Host 'What would you like to do?' -ForegroundColor Cyan
Write-Host '  [A] Add all unregistered files to the .sqlproj' -ForegroundColor Green
Write-Host '  [D] Delete all unregistered files from disk' -ForegroundColor Red
Write-Host '  [N] Do nothing' -ForegroundColor Gray
Write-Host ''

$choice = Read-Host 'Enter your choice (A/D/N)'

switch ($choice.ToUpper()) {
    'A' {
        Write-Host ''
        Write-Host 'Adding files to the project...' -ForegroundColor Cyan

        # Backup the original file
        $backupPath = "$SqlProjPath.backup_$(Get-Date -Format 'yyyyMMdd_HHmmss')"
        Copy-Item $SqlProjPath $backupPath
        Write-Host 'Backup created: ' -NoNewline -ForegroundColor Gray
        Write-Host $backupPath -ForegroundColor Gray

        # Find the last ItemGroup with Build elements
        $lastItemGroup = $sqlProj.Project.ItemGroup | Where-Object { $_.Build } | Select-Object -Last 1

        if (-not $lastItemGroup) {
            # Create a new ItemGroup if none exists
            $lastItemGroup = $sqlProj.CreateElement('ItemGroup', $sqlProj.Project.NamespaceURI)
            $sqlProj.Project.AppendChild($lastItemGroup) | Out-Null
        }

        # Add each unregistered file
        foreach ($file in $unregisteredFiles) {
            $buildElement = $sqlProj.CreateElement('Build', $sqlProj.Project.NamespaceURI)
            $buildElement.SetAttribute('Include', $file.RelativePath)
            $lastItemGroup.AppendChild($buildElement) | Out-Null
            Write-Host "  + Added: $($file.RelativePath)" -ForegroundColor Green
        }

        # Save the modified project file
        $sqlProj.Save($SqlProjPath)

        Write-Host ''
        Write-Host "Successfully added $($unregisteredFiles.Count) files to the project!" -ForegroundColor Green
    }

    'D' {
        Write-Host ''
        Write-Host "WARNING: You are about to DELETE $($unregisteredFiles.Count) files from disk!" -ForegroundColor Red
        Write-Host 'This action cannot be undone!' -ForegroundColor Red
        Write-Host ''
        $confirm = Read-Host "Type 'DELETE' to confirm"

        if ($confirm -eq 'DELETE') {
            Write-Host ''
            Write-Host 'Deleting files...' -ForegroundColor Red

            foreach ($file in $unregisteredFiles) {
                try {
                    Remove-Item -Path $file.FullPath -Force
                    Write-Host "  x Deleted: $($file.RelativePath)" -ForegroundColor Red
                } catch {
                    Write-Host "  ! Failed to delete: $($file.RelativePath) - $($_.Exception.Message)" -ForegroundColor Yellow
                }
            }

            Write-Host ''
            Write-Host 'Deletion complete!' -ForegroundColor Green
        } else {
            Write-Host 'Deletion cancelled.' -ForegroundColor Yellow
        }
    }

    'N' {
        Write-Host ''
        Write-Host 'No action taken.' -ForegroundColor Gray
    }

    default {
        Write-Host ''
        Write-Host 'Invalid choice. No action taken.' -ForegroundColor Yellow
    }
}

Write-Host ''
Write-Host 'Done!' -ForegroundColor Cyan
Read-Host 'Press Enter to exit'

