# Find-UnusedProceduresFromBothProjects.ps1
# Find procedures not used in both RestApi and Analytics projects AND not called by other procedures

# Set paths
$proceduresFile = 'C:\Users\ondrej.tichavsky\Documents\trash\4\src\Identlock2.Domain\src\IdentLock.Domain\IdentLock.Domain\Repositories\Procedures.cs'
$restApiProjectFolder = 'C:\Users\ondrej.tichavsky\Documents\trash\4\src'
$analyticsProjectFolder = 'C:\Users\ondrej.tichavsky\source\repos\IdentLock.Services.Analytics\src'
$dbProjectPath = 'C:\Users\ondrej.tichavsky\Documents\trash\database\sqlserver\IdentLock2\IdentLock2.sqlproj'
$dbProjectFolder = 'C:\Users\ondrej.tichavsky\Documents\trash\database\sqlserver\IdentLock2'

# Procedures to always exclude from removal
$excludedProcedures = @('proc_CleanDatabaseTruncate', 'proc_CleanDatabase', 'Export_BinaryData')

Write-Host '======================================================' -ForegroundColor Cyan
Write-Host 'Finding Unused Procedures in Both Projects' -ForegroundColor Cyan
Write-Host '======================================================' -ForegroundColor Cyan
Write-Host ''

# Validate paths
if (-not (Test-Path $proceduresFile)) {
    Write-Host 'ERROR: Procedures.cs not found at: ' -NoNewline -ForegroundColor Red
    Write-Host $proceduresFile -ForegroundColor Red
    Read-Host 'Press Enter to exit'
    exit 1
}

Write-Host 'Procedures file: ' -NoNewline -ForegroundColor Gray
Write-Host $proceduresFile -ForegroundColor White
Write-Host 'RestApi project: ' -NoNewline -ForegroundColor Gray
Write-Host $restApiProjectFolder -ForegroundColor White
Write-Host 'Analytics project: ' -NoNewline -ForegroundColor Gray
Write-Host $analyticsProjectFolder -ForegroundColor White
Write-Host 'Database project: ' -NoNewline -ForegroundColor Gray
Write-Host $dbProjectFolder -ForegroundColor White
Write-Host ''

# Step 1: Parse Procedures.cs to extract const names and values
Write-Host 'Step 1: Parsing Procedures.cs...' -ForegroundColor Cyan
$proceduresContent = Get-Content $proceduresFile -Raw

$procedures = @()
$matches = [regex]::Matches($proceduresContent, 'public\s+const\s+string\s+(dbo_\w+)\s*=\s*"([^"]+)"')

foreach ($match in $matches) {
    $constName = $match.Groups[1].Value
    $procValue = $match.Groups[2].Value

    # Extract just the procedure name without dbo. prefix
    $procName = $procValue -replace '^dbo\.', ''

    $procedures += @{
        ConstName = $constName
        FullValue = $procValue
        ProcName = $procName
    }
}

Write-Host "Found $($procedures.Count) procedure constants" -ForegroundColor Green
Write-Host ''

# Step 2: Load all C# files from RestApi project (excluding Procedures.cs)
Write-Host 'Step 2: Loading RestApi project C# files...' -ForegroundColor Cyan
$restApiFiles = Get-ChildItem -Path $restApiProjectFolder -Filter '*.cs' -Recurse -File | Where-Object {
    $_.FullName -ne $proceduresFile
}
Write-Host "Found $($restApiFiles.Count) C# files in RestApi project" -ForegroundColor Gray

$restApiContents = @()
foreach ($file in $restApiFiles) {
    try {
        $content = Get-Content $file.FullName -Raw -ErrorAction SilentlyContinue
        if ($content) {
            $restApiContents += $content
        }
    } catch {}
}
$restApiCombined = $restApiContents -join "`n"
Write-Host "Loaded RestApi content" -ForegroundColor Green
Write-Host ''

# Step 3: Load all C# files from Analytics project
Write-Host 'Step 3: Loading Analytics project C# files...' -ForegroundColor Cyan
if (Test-Path $analyticsProjectFolder) {
    $analyticsFiles = Get-ChildItem -Path $analyticsProjectFolder -Filter '*.cs' -Recurse -File
    Write-Host "Found $($analyticsFiles.Count) C# files in Analytics project" -ForegroundColor Gray

    $analyticsContents = @()
    foreach ($file in $analyticsFiles) {
        try {
            $content = Get-Content $file.FullName -Raw -ErrorAction SilentlyContinue
            if ($content) {
                $analyticsContents += $content
            }
        } catch {}
    }
    $analyticsCombined = $analyticsContents -join "`n"
    Write-Host "Loaded Analytics content" -ForegroundColor Green
} else {
    Write-Host 'Analytics project NOT FOUND' -ForegroundColor Yellow
    $analyticsCombined = ''
}
Write-Host ''

# Step 4: Check usage in RestApi (by const name)
Write-Host 'Step 4: Checking RestApi usage (by const name)...' -ForegroundColor Cyan
$unusedInRestApi = @()

foreach ($proc in $procedures) {
    # Check if const name is used (e.g., "dbo_proc_GetSubjectStores")
    if ($restApiCombined -notmatch [regex]::Escape($proc.ConstName)) {
        $unusedInRestApi += $proc
    }
}

Write-Host "Unused in RestApi: $($unusedInRestApi.Count) / $($procedures.Count)" -ForegroundColor Yellow
Write-Host ''

# Step 5: Check usage in Analytics (by procedure name)
Write-Host 'Step 5: Checking Analytics usage (by procedure name)...' -ForegroundColor Cyan
$unusedInAnalytics = @()

foreach ($proc in $procedures) {
    # Check if procedure name is used (e.g., "proc_GetSubjectStores" or "dbo.proc_GetSubjectStores")
    $isUsed = $false

    if ($analyticsCombined -match [regex]::Escape($proc.ProcName) -or 
        $analyticsCombined -match [regex]::Escape($proc.FullValue)) {
        $isUsed = $true
    }

    if (-not $isUsed) {
        $unusedInAnalytics += $proc
    }
}

Write-Host "Unused in Analytics: $($unusedInAnalytics.Count) / $($procedures.Count)" -ForegroundColor Yellow
Write-Host ''

# Step 6: Find intersection (unused in BOTH projects)
Write-Host 'Step 6: Finding intersection (unused in BOTH projects)...' -ForegroundColor Cyan
$unusedInBothProjects = @()

foreach ($proc in $unusedInRestApi) {
    $foundInAnalyticsUnused = $unusedInAnalytics | Where-Object { $_.ConstName -eq $proc.ConstName }
    if ($foundInAnalyticsUnused) {
        $unusedInBothProjects += $proc
    }
}

Write-Host "Unused in BOTH projects: $($unusedInBothProjects.Count)" -ForegroundColor Yellow
Write-Host ''

# Step 7: Load all SQL procedure files and find which procedures call other procedures
Write-Host 'Step 7: Analyzing SQL procedure calls...' -ForegroundColor Cyan
$sqlFiles = Get-ChildItem -Path $dbProjectFolder -Filter "*.sql" -Recurse -File | Where-Object {
    $_.FullName -notmatch '\\Migrations\\' -and
    $_.FullName -notmatch '\\obj\\' -and
    $_.FullName -match '\\StoredProcedures\\'
}

Write-Host "Found $($sqlFiles.Count) SQL procedure files" -ForegroundColor Gray

# Build a combined content of all SQL procedures
$allSqlContent = ""
foreach ($sqlFile in $sqlFiles) {
    try {
        $content = Get-Content $sqlFile.FullName -Raw -ErrorAction SilentlyContinue
        if ($content) {
            $allSqlContent += "`n" + $content
        }
    } catch {}
}

Write-Host "Loaded SQL content" -ForegroundColor Green

# Find procedures that are NOT called by any other procedure
$unusedInSqlProcedures = @()

foreach ($proc in $procedures) {
    $procName = $proc.ProcName

    # Check if this procedure is called in any SQL file
    # Look for patterns like: EXEC proc_Name, EXECUTE proc_Name, EXEC dbo.proc_Name, etc.
    $isCalledInSql = $false

    # Pattern to match EXEC/EXECUTE calls
    $patterns = @(
        "EXEC\s+\[?dbo\]?\.\[?$procName\]?",
        "EXEC\s+\[?$procName\]?",
        "EXECUTE\s+\[?dbo\]?\.\[?$procName\]?",
        "EXECUTE\s+\[?$procName\]?"
    )

    foreach ($pattern in $patterns) {
        if ($allSqlContent -match $pattern) {
            $isCalledInSql = $true
            break
        }
    }

    if (-not $isCalledInSql) {
        $unusedInSqlProcedures += $proc
    }
}

Write-Host "Not called by other procedures: $($unusedInSqlProcedures.Count) / $($procedures.Count)" -ForegroundColor Yellow
Write-Host ''

# Step 8: Find intersection of procedures unused in BOTH projects AND not called by other procedures
Write-Host 'Step 8: Finding final intersection (unused in projects AND not called by procedures)...' -ForegroundColor Cyan
$unusedInBoth = @()

foreach ($proc in $unusedInBothProjects) {
    $foundInSqlUnused = $unusedInSqlProcedures | Where-Object { $_.ConstName -eq $proc.ConstName }
    if ($foundInSqlUnused) {
        # Also check if it's not in the excluded list
        if ($excludedProcedures -notcontains $proc.ProcName) {
            $unusedInBoth += $proc
        }
    }
}

Write-Host "Final intersection (truly unused): $($unusedInBoth.Count)" -ForegroundColor Red
Write-Host ''

Write-Host 'Step 9: Finding SQL files and filtering Core procedures...' -ForegroundColor Cyan

# Step 9: Find corresponding SQL files in database project and filter out Core procedures
$sqlFilesToRemove = @()
$coreProcedures = @()

foreach ($proc in $unusedInBoth) {
    # Try to find the SQL file for this procedure
    $procName = $proc.ProcName
    $possibleFiles = Get-ChildItem -Path $dbProjectFolder -Filter "*.sql" -Recurse -File | Where-Object {
        $_.FullName -notmatch '\\Migrations\\' -and
        $_.FullName -notmatch '\\obj\\' -and
        ($_.Name -match $procName -or
        (Get-Content $_.FullName -Raw) -match "CREATE\s+(?:OR\s+ALTER\s+)?PROCEDURE\s+(?:\[?dbo\]?\.)?\[?$procName\]?")
    }

    $isCoreProcedure = $false

    foreach ($file in $possibleFiles) {
        # Check if the file is in StoredProcedures\Core directory
        if ($file.FullName -match '\\StoredProcedures\\Core\\') {
            $isCoreProcedure = $true
            break
        }

        $sqlFilesToRemove += @{
            Procedure = $proc
            FullPath = $file.FullName
            RelativePath = $file.FullName.Substring($dbProjectFolder.Length + 1)
            FileName = $file.Name
        }
    }

    if ($isCoreProcedure) {
        $coreProcedures += $proc
    }
}

# Filter out core procedures from unusedInBoth
$unusedInBoth = $unusedInBoth | Where-Object { 
    $proc = $_
    -not ($coreProcedures | Where-Object { $_.ConstName -eq $proc.ConstName })
}

Write-Host ''
Write-Host '======================================================' -ForegroundColor Cyan
Write-Host 'RESULTS' -ForegroundColor Cyan
Write-Host '======================================================' -ForegroundColor Cyan
Write-Host "Total procedures in Procedures.cs: $($procedures.Count)" -ForegroundColor White
Write-Host "Unused in RestApi only: $($unusedInRestApi.Count)" -ForegroundColor Yellow
Write-Host "Unused in Analytics only: $($unusedInAnalytics.Count)" -ForegroundColor Yellow
Write-Host "Unused in BOTH C# projects: $($unusedInBothProjects.Count)" -ForegroundColor Yellow
Write-Host "Not called by other SQL procedures: $($unusedInSqlProcedures.Count)" -ForegroundColor Yellow
Write-Host "FINAL: Unused everywhere (projects + SQL): $($unusedInBoth.Count)" -ForegroundColor Red
if ($coreProcedures.Count -gt 0) {
    Write-Host "Excluded (Core procedures): $($coreProcedures.Count)" -ForegroundColor Magenta
}
Write-Host ''

if ($unusedInBoth.Count -eq 0) {
    Write-Host 'All procedures are used in at least one place (or are in StoredProcedures\Core)!' -ForegroundColor Green
    Read-Host 'Press Enter to exit'
    exit 0
}

# Display unused procedures
Write-Host 'Procedures unused EVERYWHERE (C# projects + SQL procedures, excluding Core):' -ForegroundColor Red
Write-Host ('=' * 80) -ForegroundColor Red
foreach ($proc in $unusedInBoth) {
    Write-Host "  - $($proc.ConstName)" -ForegroundColor White
    Write-Host "    SQL: $($proc.FullValue)" -ForegroundColor Gray
}
Write-Host ('=' * 80) -ForegroundColor Red
Write-Host ''

if ($sqlFilesToRemove.Count -gt 0) {
    Write-Host "Found $($sqlFilesToRemove.Count) SQL files to remove:" -ForegroundColor Yellow
    foreach ($file in $sqlFilesToRemove) {
        Write-Host "  - $($file.RelativePath)" -ForegroundColor Gray
    }
} else {
    Write-Host "Warning: Could not find SQL files for these procedures" -ForegroundColor Yellow
}
Write-Host ''

# Ask what to do
Write-Host 'What would you like to do?' -ForegroundColor Cyan
Write-Host '  [R] Remove these procedures from database project' -ForegroundColor Red
Write-Host '  [N] Do nothing' -ForegroundColor Gray
Write-Host ''

$choice = Read-Host 'Enter your choice (R/N)'

if ($choice.ToUpper() -eq 'R') {
    if ($sqlFilesToRemove.Count -eq 0) {
        Write-Host ''
        Write-Host 'No SQL files found to remove!' -ForegroundColor Yellow
        Read-Host 'Press Enter to exit'
        exit 0
    }

    Write-Host ''
    Write-Host "WARNING: You are about to DELETE $($sqlFilesToRemove.Count) procedure files!" -ForegroundColor Red
    Write-Host 'This will:' -ForegroundColor Red
    Write-Host '  1. Delete the .sql files from disk' -ForegroundColor Red
    Write-Host '  2. Remove the entries from the .sqlproj file' -ForegroundColor Red
    Write-Host 'This action cannot be undone!' -ForegroundColor Red
    Write-Host ''
    $confirm = Read-Host "Type 'REMOVE' to confirm"

    if ($confirm -eq 'REMOVE') {
        Write-Host ''
        Write-Host 'Processing removal...' -ForegroundColor Cyan
        Write-Host ''

        # Load the .sqlproj XML
        [xml]$sqlProj = Get-Content $dbProjectPath

        $removedCount = 0
        $failedCount = 0

        foreach ($file in $sqlFilesToRemove) {
            try {
                # Delete the file
                if (Test-Path $file.FullPath) {
                    Remove-Item -Path $file.FullPath -Force
                    Write-Host "  x Deleted file: $($file.RelativePath)" -ForegroundColor Red
                }

                # Remove from sqlproj
                $pathToRemove = $file.RelativePath.Replace('/', '\')
                $buildElements = $sqlProj.Project.ItemGroup.Build | Where-Object { $_.Include -eq $pathToRemove }

                foreach ($element in $buildElements) {
                    $element.ParentNode.RemoveChild($element) | Out-Null
                }

                $removedCount++

            } catch {
                Write-Host "  ! Failed to remove: $($file.FileName) - $($_.Exception.Message)" -ForegroundColor Yellow
                $failedCount++
            }
        }

        # Save the modified sqlproj
        $sqlProj.Save($dbProjectPath)

        Write-Host ''
        Write-Host "Successfully removed $removedCount procedure files" -ForegroundColor Green
