# PowerShell script to fetch multiple Git repositories and their submodules

# Define the list of repositories to fetch
$repositories = @(
    "C:\Users\ondrej.tichavsky\Documents\repos\RD_IDENTLOCK2_RESTAPI\",
    "C:\Users\ondrej.tichavsky\Documents\trash\4\",
    "C:\Users\ondrej.tichavsky\Documents\trash\database\",
    "C:\Users\ondrej.tichavsky\Documents\repos\DbReflector\",
    "C:\Users\ondrej.tichavsky\source\repos\IDENTLOCK2_DESK\"
)

# Function to fetch a repository and its submodules
function Fetch-Repository {
    param (
        [string]$repoPath
    )

    Write-Host ""
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host "Processing: $repoPath" -ForegroundColor Cyan
    Write-Host "========================================" -ForegroundColor Cyan

    # Check if directory exists
    if (-not (Test-Path $repoPath)) {
        Write-Host "ERROR: Directory does not exist: $repoPath" -ForegroundColor Red
        return
    }

    # Check if it's a git repository
    $gitPath = Join-Path $repoPath ".git"
    if (-not (Test-Path $gitPath)) {
        Write-Host "ERROR: Not a git repository: $repoPath" -ForegroundColor Red
        return
    }

    try {
        # Change to repository directory
        Push-Location $repoPath

        # Fetch main repository
        Write-Host "Fetching main repository..." -ForegroundColor Yellow
        git fetch --all --prune

        if ($LASTEXITCODE -eq 0) {
            Write-Host "[OK] Main repository fetched successfully" -ForegroundColor Green
        } else {
            Write-Host "[FAIL] Failed to fetch main repository" -ForegroundColor Red
        }

        # Check if repository has submodules
        $gitmodulesPath = Join-Path $repoPath ".gitmodules"
        if (Test-Path $gitmodulesPath) {
            Write-Host "Fetching submodules..." -ForegroundColor Yellow
            git submodule update --init --recursive
            git submodule foreach --recursive git fetch --all --prune

            if ($LASTEXITCODE -eq 0) {
                Write-Host "[OK] Submodules fetched successfully" -ForegroundColor Green
            } else {
                Write-Host "[FAIL] Failed to fetch submodules" -ForegroundColor Red
            }
        } else {
            Write-Host "No submodules found" -ForegroundColor Gray
        }
    }
    catch {
        Write-Host "ERROR: $_" -ForegroundColor Red
    }
    finally {
        # Return to original directory
        Pop-Location
    }
}

# Main execution
Write-Host ""
Write-Host "========================================"
Write-Host "  Git Fetch Multiple Repositories"
Write-Host "========================================"
Write-Host ""

$startTime = Get-Date

# Process each repository
foreach ($repo in $repositories) {
    Fetch-Repository -repoPath $repo
}

$endTime = Get-Date
$duration = $endTime - $startTime

Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Summary" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Total repositories processed: $($repositories.Count)" -ForegroundColor White
Write-Host "Total time: $($duration.ToString('mm\:ss'))" -ForegroundColor White
Write-Host ""
Write-Host "All operations completed!" -ForegroundColor Green

